diff --git a/packages/ui/src/engine/pixel-characters.ts b/packages/ui/src/engine/pixel-characters.ts
index 4b7e0a2..f9a6e3d 100644
--- a/packages/ui/src/engine/pixel-characters.ts
+++ b/packages/ui/src/engine/pixel-characters.ts
@@ -1037,60 +1037,153 @@ function drawTiledFloor(ctx: CanvasRenderingContext2D, x: number, y: number, w: number, h: number, type: CharacterType) {
-  const ft: Record<CharacterType, string> = {
-    king: 'carpet', nobility: 'wood', knight: 'wood', squire: 'wood',
-    healer: 'dark_stone', sentinel: 'stone', scribe: 'wood', judge: 'wood', blacksmith: 'stone',
-  };
-  const tile = 16;
-  const kind = ft[type];
-
-  if (kind === 'wood') {
-    const cols = ['#3e2a18', '#4a3420', '#3a2614', '#443018'];
-    ctx.fillStyle = '#3e2a18'; ctx.fillRect(x, y, w, h);
-    const pW = 28;
-    for (let r = 0; r < Math.ceil(h / tile); r++) {
-      for (let c = 0; c < Math.ceil(w / pW) + 1; c++) {
-        const px = x + c * pW + (r % 2) * (pW / 2);
-        ctx.fillStyle = cols[(c + r * 3) % cols.length];
-        ctx.fillRect(px + 1, y + r * tile + 1, pW - 1, tile - 1);
-        ctx.fillStyle = 'rgba(0,0,0,0.08)';
-        ctx.fillRect(px + 4, y + r * tile + 3, pW - 8, 1);
-        ctx.fillRect(px + 6, y + r * tile + 7, pW - 10, 1);
-        ctx.fillRect(px + 3, y + r * tile + 11, pW - 6, 1);
-      }
-      ctx.fillStyle = 'rgba(0,0,0,0.15)';
-      ctx.fillRect(x, y + r * tile, w, 1);
-    }
-  } else if (kind === 'stone' || kind === 'dark_stone') {
-    const bc = kind === 'dark_stone' ? '#1a2030' : '#2c3040';
-    const lc = kind === 'dark_stone' ? '#222838' : '#343848';
-    ctx.fillStyle = bc; ctx.fillRect(x, y, w, h);
-    for (let r = 0; r < Math.ceil(h / tile); r++) {
-      for (let c = 0; c < Math.ceil(w / tile); c++) {
-        const tx = x + c * tile, ty = y + r * tile;
-        const hash = ((c * 17 + r * 31) & 0xFF) / 255;
-        ctx.fillStyle = hash > 0.5 ? lc : bc;
-        ctx.fillRect(tx + 1, ty + 1, tile - 2, tile - 2);
-        if (hash > 0.85) {
-          ctx.fillStyle = 'rgba(0,0,0,0.2)';
-          ctx.fillRect(tx + 4, ty + 6, 8, 1);
-          ctx.fillRect(tx + 7, ty + 4, 1, 6);
-        }
-      }
-    }
-  } else if (kind === 'carpet') {
-    ctx.fillStyle = '#2c3040'; ctx.fillRect(x, y, w, h);
-    for (let c = 0; c < Math.ceil(w / tile); c++)
-      for (let r = 0; r < Math.ceil(h / tile); r++) {
-        ctx.fillStyle = ((c + r) % 2 === 0) ? '#303848' : '#282e3e';
-        ctx.fillRect(x + c * tile, y + r * tile, tile, tile);
-      }
-    const cw = w * 0.35, cx = x + (w - cw) / 2;
-    ctx.fillStyle = '#6b1515'; ctx.fillRect(cx, y, cw, h);
-    ctx.fillStyle = '#8b2020'; ctx.fillRect(cx + 3, y, cw - 6, h);
-    ctx.fillStyle = P.gold[2];
-    ctx.fillRect(cx + 1, y, 2, h);
-    ctx.fillRect(cx + cw - 3, y, 2, h);
-    for (let dy = 0; dy < h; dy += 20) {
-      ctx.fillStyle = P.gold[1];
-      ctx.fillRect(cx + cw / 2 - 2, y + dy + 6, 4, 4);
-    }
-  }
+  const tile = 16;
+
+  // Tile patterns for stone floor variants
+  function drawStoneTile(tx: number, ty: number, base: string, light: string, dark: string) {
+    ctx.fillStyle = base;
+    ctx.fillRect(tx, ty, tile, tile);
+    // Random cracks and patterns
+    const hash = ((tx * 17 + ty * 31) & 0xFF) / 255;
+    if (hash > 0.7) {
+      ctx.fillStyle = dark;
+      ctx.fillRect(tx + 3, ty + 3, tile - 6, 2);
+      ctx.fillRect(tx + 3, ty + 3, 2, tile - 6);
+    } else if (hash > 0.4) {
+      ctx.fillStyle = light;
+      ctx.fillRect(tx + 6, ty + 6, tile - 12, 1);
+      ctx.fillRect(tx + 6, ty + 6, 1, tile - 12);
+    }
+    // Subtle color variation overlay
+    const variation = (hash - 0.5) * 0.2;
+    ctx.fillStyle = `rgba(255,255,255,${variation})`;
+    ctx.fillRect(tx, ty, tile, tile);
+  }
+
+  // Tile patterns for wood floor variants
+  function drawWoodTile(tx: number, ty: number, colors: string[]) {
+    const pW = 28;
+    // Draw staggered planks
+    for (let r = 0; r < 2; r++) {
+      const rowY = ty + r * (tile / 2);
+      for (let c = 0; c < Math.ceil((w + pW) / pW); c++) {
+        const px = tx + c * pW + (r % 2) * (pW / 2);
+        ctx.fillStyle = colors[(c + r * 3) % colors.length];
+        ctx.fillRect(px + 1, rowY + 1, pW - 1, tile / 2 - 1);
+        ctx.fillStyle = 'rgba(0,0,0,0.08)';
+        ctx.fillRect(px + 4, rowY + 3, pW - 8, 1);
+        ctx.fillRect(px + 6, rowY + 7, pW - 10, 1);
+        ctx.fillRect(px + 3, rowY + 11, pW - 6, 1);
+      }
+    }
+    ctx.fillStyle = 'rgba(0,0,0,0.15)';
+    for (let r = 0; r < Math.ceil(h / tile); r++) {
+      ctx.fillRect(tx, ty + r * tile, w, 1);
+    }
+  }
+
+  // Tile patterns for carpet floor variants
+  function drawCarpetTile(tx: number, ty: number) {
+    ctx.fillStyle = ((Math.floor(tx / tile) + Math.floor(ty / tile)) % 2 === 0) ? '#303848' : '#282e3e';
+    ctx.fillRect(tx, ty, tile, tile);
+  }
+
+  const floorType: Record<CharacterType, string> = {
+    king: 'carpet',
+    nobility: 'wood',
+    knight: 'wood',
+    squire: 'stone_varied',
+    healer: 'dark_stone',
+    sentinel: 'stone',
+    scribe: 'wood',
+    judge: 'wood',
+    blacksmith: 'stone',
+  };
+
+  const kind = floorType[type];
+
+  if (kind === 'wood') {
+    const woodColors = ['#3e2a18', '#4a3420', '#3a2614', '#443018'];
+    drawWoodTile(x, y, woodColors);
+  } else if (kind === 'stone' || kind === 'dark_stone') {
+    const baseColor = kind === 'dark_stone' ? '#1a2030' : '#2c3040';
+    const lightColor = kind === 'dark_stone' ? '#222838' : '#343848';
+    ctx.fillStyle = baseColor;
+    ctx.fillRect(x, y, w, h);
+    for (let r = 0; r < Math.ceil(h / tile); r++) {
+      for (let c = 0; c < Math.ceil(w / tile); c++) {
+        const tx = x + c * tile;
+        const ty = y + r * tile;
+        const hash = ((c * 17 + r * 31) & 0xFF) / 255;
+        ctx.fillStyle = hash > 0.5 ? lightColor : baseColor;
+        ctx.fillRect(tx + 1, ty + 1, tile - 2, tile - 2);
+        // Add cracks and patterns
+        if (hash > 0.85) {
+          ctx.fillStyle = 'rgba(0,0,0,0.2)';
+          ctx.fillRect(tx + 4, ty + 6, 8, 1);
+          ctx.fillRect(tx + 7, ty + 4, 1, 6);
+        }
+      }
+    }
+  } else if (kind === 'stone_varied') {
+    const base = '#2e2e3e';
+    const light = '#3a3a4a';
+    const dark = '#252535';
+    ctx.fillStyle = base;
+    ctx.fillRect(x, y, w, h);
+    for (let r = 0; r < Math.ceil(h / tile); r++) {
+      for (let c = 0; c < Math.ceil(w / tile); c++) {
+        const tx = x + c * tile;
+        const ty = y + r * tile;
+        drawStoneTile(tx, ty, base, light, dark);
+      }
+    }
+  } else if (kind === 'carpet') {
+    ctx.fillStyle = '#2c3040';
+    ctx.fillRect(x, y, w, h);
+    for (let c = 0; c < Math.ceil(w / tile); c++) {
+      for (let r = 0; r < Math.ceil(h / tile); r++) {
+        drawCarpetTile(x + c * tile, y + r * tile);
+      }
+    }
+    const cw = w * 0.35, cx = x + (w - cw) / 2;
+    ctx.fillStyle = '#6b1515';
+    ctx.fillRect(cx, y, cw, h);
+    ctx.fillStyle = '#8b2020';
+    ctx.fillRect(cx + 3, y, cw - 6, h);
+    ctx.fillStyle = P.gold[2];
+    ctx.fillRect(cx + 1, y, 2, h);
+    ctx.fillRect(cx + cw - 3, y, 2, h);
+    for (let dy = 0; dy < h; dy += 20) {
+      ctx.fillStyle = P.gold[1];
+      ctx.fillRect(cx + cw / 2 - 2, y + dy + 6, 4, 4);
+    }
+  }
+
